const { time, times, duration_minutes, section, weekdays } = msg.payload || {};

msg.payload = {
    command: "schedule",
    action: "create",
    times: Array.isArray(times) && times.length ? times : [time],
    duration_minutes,
    valve_pin: section,
    weekdays
};

return msg;

const output = String(msg.payload || "").trim();

if (!output) {
    return null;
}

msg.payload = output;
return msg;

if (!msg.payload) {
    return null;
}

msg.topic = "schedule_create_error";
msg.payload = String(msg.payload).replace(/^Error:\s*/, "").trim();
return msg;

const text = String(msg.payload || "").trim();
let records = [];

if (text) {
    const parsed = JSON.parse(text);
    records = Array.isArray(parsed) ? parsed : [parsed];
}

function firstTime(record) {
    if (Array.isArray(record.times) && record.times.length) return String(record.times[0]);
    return String(record.time || "");
}

records.sort((a, b) => firstTime(a).localeCompare(firstTime(b)));

msg.topic = "schedules";
msg.payload = records;
return msg;

if (!msg.payload) {
    return null;
}

msg.topic = "schedule_error";
msg.payload = String(msg.payload).replace(/^Error:\s*/, "").trim();
return [msg, msg];

const { id, time, times, duration_minutes, valve_pin, weekdays } = msg.payload || {};

msg.payload = {
    command: "schedule",
    action: "update",
    id,
    times: Array.isArray(times) && times.length ? times : [time],
    duration_minutes,
    valve_pin,
    weekdays
};

return msg;

const output = String(msg.payload || "").trim();

if (!output) {
    return null;
}

msg.payload = output;
return msg;

if (!msg.payload) {
    return null;
}

msg.topic = "schedule_update_error";
msg.payload = String(msg.payload).replace(/^Error:\s*/, "").trim();
return msg;

const text = String(msg.payload || "").trim();
msg.topic = "valves";
msg.payload = text ? JSON.parse(text) : [];
return msg;

const { action, valve_pin, duration_minutes, id } = msg.payload || {};

msg.payload = {
    command: "valve",
    action: "manual",
    pin: valve_pin,
    valve_action: action,
    schedule_id: id
};
if (action === "on") {
    msg.payload.duration_minutes = duration_minutes;
}

return msg;

records = []
msg.payload = msg.payload.replace(/}/g, '},,')
records = msg.payload.split(',,')

records.pop();

for (let i = 0; i < records.length; i++) {
    records[i] = JSON.parse(records[i])
}


records.sort((a,b) => {
    return a.time > b.time;
})

//if (records.length > 0) {
    msg.payload = records.reverse();
    return msg;
//}

const { action, start_date = "", end_date = "" } = msg.payload || {};

msg.payload = { command: "history", action, start_date, end_date };

return msg;

const payload = msg.payload || {};

if (payload.ui_action === "delete") {
    msg.payload = payload.id;
    return [msg, null, null, null];
}

if (payload.ui_action === "edit") {
    delete payload.ui_action;
    msg.payload = payload;
    return [null, msg, null, null];
}

if (payload.ui_action === "manual") {
    msg.topic = "manual_feedback";
    msg.payload = { id: payload.id, action: payload.action, valve_pin: payload.valve_pin, duration_minutes: payload.duration_minutes };
    return [null, null, msg, null];
}

if (payload.ui_action === "toggle_enabled") {
    msg.payload = { id: payload.id, enabled: payload.enabled };
    return [null, null, null, msg];
}

return [null, null, null, null];

const { id, enabled } = msg.payload || {};
const value = enabled === true || Number(enabled) === 1 ? 1 : 0;

msg.payload = { command: "schedule", action: "enabled", id, enabled: value };

return msg;

const output = String(msg.payload || "").trim();

if (!output) {
    return null;
}

msg.topic = "schedule_enabled";
try {
    msg.payload = JSON.parse(output);
} catch (err) {
    msg.payload = output;
}
return msg;

if (!msg.payload) {
    return null;
}

msg.topic = "schedule_enabled_error";
msg.payload = String(msg.payload).replace(/^Error:\s*/, "").trim();
return msg;

const payload = msg.payload || {};
const HISTORY_RETENTION_ALLOWED_DAYS = [7, 15, 30, 90];

function fail(message) {
    return [null, { topic: "password_change_error", payload: message }, null, null, null, null];
}
function valveFail(message) {
    return [null, { topic: "valve_error", payload: message }, null, null, null, null];
}
function historyRetentionFail(message) {
    return [null, null, null, null, null, { topic: "history_retention_error", payload: message }];
}

if (payload.ui_action === "change_password") {
    const username = String(payload.username || "admin");
    const current = String(payload.current_password || "");
    const next = String(payload.new_password || "");
    const confirm = String(payload.confirm_password || "");

    if (!current || !next || !confirm) {
        return fail("Preencha todos os campos de senha.");
    }
    if (next.length < 8) {
        return fail("A nova senha deve ter pelo menos 8 caracteres.");
    }
    if (next !== confirm) {
        return fail("A confirmação da senha não confere.");
    }

    msg.payload = { command: "auth", action: "change-password", username, current_password: current, new_password: next, confirm_password: confirm };
    return [msg, null, null, null, null, null];
}

if (payload.ui_action === "add_valve") {
    const pin = String(payload.pin || "").trim();
    const section = String(payload.section || "").trim();
    if (!pin || Number(pin) < 1 || !section) {
        return valveFail("Informe pino e nome da seção.");
    }
    msg.payload = { command: "valve", action: "add", pin, section };
    return [null, null, msg, null, null, null];
}

if (payload.ui_action === "update_valve") {
    const id = String(payload.id || "").trim();
    const pin = String(payload.pin || "").trim();
    const section = String(payload.section || "").trim();
    if (!id || !pin || Number(pin) < 1 || !section) {
        return valveFail("Informe id, pino e nome da seção.");
    }
    msg.payload = { command: "valve", action: "update", id, pin, section };
    return [null, null, null, msg, null, null];
}

if (payload.ui_action === "delete_valve") {
    const id = String(payload.id || "").trim();
    if (!id) {
        return valveFail("Informe a seção a excluir.");
    }
    msg.payload = { command: "valve", action: "delete", id };
    return [null, null, null, null, msg, null];
}

if (payload.ui_action === "update_history_retention") {
    const days = Number(payload.retention_days);
    if (!HISTORY_RETENTION_ALLOWED_DAYS.includes(days)) {
        return historyRetentionFail("Selecione um período de retenção válido.");
    }
    msg.payload = { command: "history-retention", value: days };
    return [null, null, null, null, null, msg];
}

return null;

msg.topic = "password_changed";
msg.payload = "Senha alterada.";
return msg;

msg.topic = "password_change_error";
msg.payload = String(msg.payload || "Não foi possível alterar a senha.").replace(/^Error:\s*/, "").trim();
return msg;

const text = String(msg.payload || "").trim();
let health = {};

if (text) {
    try {
        health = JSON.parse(text);
    } catch (err) {
        health = { status: "offline", error: text };
    }
}

const online = health.status === "online";
msg.topic = "system_health";
msg.payload = {
    status: online ? "online" : "offline",
    label: online ? "Sistema online" : "Sistema offline",
    checked_at: new Date().toISOString(),
    last_seen_at: health.last_seen_at || null,
    age_seconds: health.age_seconds ?? null,
    component: health.component || "irrigation-core"
};
return msg;

msg.topic = "valve_saved";
msg.payload = "Seção salva.";
return msg;

msg.topic = "valve_saved";
msg.payload = "Seção salva.";
return msg;

msg.topic = "valve_deleted";
msg.payload = "Seção excluída.";
return msg;

msg.topic = "valve_error";
msg.payload = String(msg.payload || "Não foi possível salvar a seção.").replace(/^Error:\s*/, "").trim();
return msg;

msg.topic = "history_retention_saved";
msg.payload = "Período de retenção atualizado.";
return msg;

msg.topic = "history_retention_error";
msg.payload = String(msg.payload || "Não foi possível atualizar o período de retenção.").replace(/^Error:\s*/, "").trim();
return msg;

const text = String(msg.payload || "").trim();
let retention = {};

if (text) {
    try {
        retention = JSON.parse(text);
    } catch (err) {
        retention = {};
    }
}

msg.topic = "history_retention";
msg.payload = { retention_days: Number(retention.retention_days) || 7 };
return msg;

const payload = msg.payload || {};
const actions = { add_sensor: "add", update_sensor: "update", toggle_sensor: "enabled", delete_sensor: "delete" };
const action = actions[payload.ui_action];
if (!action) return null;

function fail(message) {
    return [null, { topic: "sensor_error", payload: message }];
}
const id = String(payload.id || "").trim();
if (action !== "add" && !id) return fail("Informe o sensor a atualizar.");
if (action === "delete") {
    msg.sensor_action = action;
    msg.payload = { command: "sensor", action, id };
    return [msg, null];
}
if (action === "enabled") {
    const enabled = Number(payload.enabled);
    if (![0, 1].includes(enabled)) return fail("Informe um estado válido para o sensor.");
    msg.sensor_action = action;
    msg.payload = { command: "sensor", action, id, enabled };
    return [msg, null];
}
const name = String(payload.name || "").trim();
const kind = String(payload.kind || "").trim();
const supportedKinds = ["reservoir_level", "flow", "soil_moisture", "line_pressure", "rain"];
const enabled = Number(payload.enabled);
if (!name) return fail("Informe o nome do sensor.");
if (!supportedKinds.includes(kind)) return fail("Selecione um tipo de sensor válido.");
if (![0, 1].includes(enabled)) return fail("Informe um estado válido para o sensor.");
msg.sensor_action = action;
msg.payload = { command: "sensor", action, name, kind, enabled, valve_id: payload.valve_id || null };
if (id) msg.payload.id = id;
return [msg, null];

const topics = { add: "sensor_saved", update: "sensor_saved", enabled: "sensor_enabled", delete: "sensor_deleted" };
msg.topic = topics[msg.sensor_action] || "sensor_saved";
return msg;

msg.topic = "sensor_error";
msg.payload = String(msg.payload || "Não foi possível atualizar o sensor.").replace(/^Error:\s*/, "").trim();
return msg;

const text = String(msg.payload || "").trim();
let sensors = [];
try { sensors = text ? JSON.parse(text) : []; } catch (err) { sensors = []; }
msg.topic = "sensors";
msg.payload = Array.isArray(sensors) ? sensors : [];
return msg;

const payload = msg.payload || {};
if (payload.ui_action === "load_discord_config") {
    return [null, null, msg];
}

const actions = { save_discord_webhook: "save-webhook", delete_discord_webhook: "delete-webhook", toggle_discord_event: "set-event" };
const action = actions[payload.ui_action];
if (!action) return null;

function fail(message) {
    return [null, { topic: "notification_error", payload: message }, null];
}
msg.notification_action = action;
msg.payload = { command: "notifications", action };
if (action === "save-webhook") {
    const webhookUrl = String(payload.webhook_url || "").trim();
    if (!webhookUrl) return fail("Informe a URL do webhook do Discord.");
    msg.payload.webhook_url = webhookUrl;
}
if (action === "set-event") {
    const enabled = Number(payload.enabled);
    const event = String(payload.event || "").trim();
    if (!event || ![0, 1].includes(enabled)) return fail("Informe um evento e estado válidos.");
    msg.payload.event = event;
    msg.payload.enabled = enabled;
}
return [msg, null, null];

const topics = { "save-webhook": "notification_saved", "delete-webhook": "notification_deleted", "set-event": "notification_event_saved" };
msg.topic = topics[msg.notification_action] || "notification_saved";
return msg;

msg.topic = "notification_error";
msg.payload = String(msg.payload || "Não foi possível atualizar o Discord.").replace(/^Error:\s*/, "").trim();
return msg;

const text = String(msg.payload || "").trim();
let config = { webhook_url: null, events: {} };
try { config = text ? JSON.parse(text) : config; } catch (err) {}
msg.topic = "notification_config";
msg.payload = config;
return msg;
